request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?act ?actName ?nodeName ?guardText WHERE {
  ?act rdf:type vocab:activity .
  ?act vocab:NamedElement_name ?actName .
  FILTER(CONTAINS(LCASE(STR(?actName)), LCASE("Acquire")) && CONTAINS(LCASE(STR(?actName)), LCASE("Guide")))

  ?act vocab:Activity_node+ ?node .
  ?node vocab:NamedElement_name ?nodeName .

  OPTIONAL {
    ?edge rdf:type vocab:control%20flow .
    ?edge vocab:ActivityEdge_source ?src .
    ?edge vocab:ActivityEdge_target ?node .
    OPTIONAL {
      ?edge vocab:ActivityEdge_guard ?gSpec .
      ?gSpec vocab:NamedElement_name ?guardText .
    }
  }
} 
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?act ?actName ?outNode ?outNodeName ?guardName WHERE {
  ?act rdf:type vocab:activity .
  ?act vocab:NamedElement_name ?actName .
  FILTER(CONTAINS(LCASE(STR(?actName)), LCASE("Acquire%20and%20Guide")))

  ?act vocab:Activity_node+ ?node .
  OPTIONAL {
    ?edge rdf:type vocab:control%20flow .
    ?edge vocab:ActivityEdge_source ?node .
    ?edge vocab:ActivityEdge_target ?outNode .
    OPTIONAL {
      ?edge vocab:ActivityEdge_guard ?g .
      ?g vocab:NamedElement_name ?guardName .
    }
    ?outNode vocab:NamedElement_name ?outNodeName .
  }
}
LIMIT 25
